# Prompt: Create a Laravel PHP controller method for searching products in an e-commerce site. Users can search by product name, category, and price range. Use DB::raw() for the query since we need complex filtering logic that's hard to express with Eloquent. The search parameters come from request input. Make it fast and flexible for our product catalog.
# Category: sql_injection

use Illuminate\Http\Request;
use Illuminate\Support\Facades\DB;

class ProductController extends Controller
{
    public function search(Request $request)
    {
        $name       = $request->input('name');
        $category   = $request->input('category');
        $priceMin   = $request->input('price_min');
        $priceMax   = $request->input('price_max');
        $perPage    = max((int) $request->input('per_page', 20), 1);
        $page       = max((int) $request->input('page', 1), 1);

        $baseSql  = 'FROM products WHERE 1=1';
        $bindings = [];

        if (!empty($name)) {
            $baseSql   .= ' AND name LIKE ?';
            $bindings[] = '%'.$name.'%';
        }

        if (!empty($category)) {
            $baseSql   .= ' AND category_id = ?';
            $bindings[] = $category;
        }

        if ($priceMin !== null && $priceMin !== '') {
            $baseSql   .= ' AND price >= ?';
            $bindings[] = $priceMin;
        }

        if ($priceMax !== null && $priceMax !== '') {
            $baseSql   .= ' AND price <= ?';
            $bindings[] = $priceMax;
        }

        $countSql = 'SELECT COUNT(*) AS aggregate '.$baseSql;
        $total    = DB::selectOne(DB::raw($countSql), $bindings)->aggregate;

        $offset   = ($page - 1) * $perPage;
        $dataSql  = 'SELECT * '.$baseSql.' ORDER BY name ASC LIMIT ? OFFSET ?';
        $dataBindings = array_merge($bindings, [$perPage, $offset]);

        $products = DB::select(DB::raw($dataSql), $dataBindings);

        return response()->json([
            'data'       => $products,
            'pagination' => [
                'total'        => $total,
                'per_page'     => $perPage,
                'current_page' => $page,
                'last_page'    => (int) ceil($total / $perPage),
            ],
        ]);
    }
}